script:
// Function to format currency according to Frappe settings
const format_val = (v) => {
    return frappe.format(v, { fieldtype: 'Currency', currency: 'INR' })
        .replace("₹", "")
        .trim();
};

frappe.call({
    method: "tridax.tridaxapp.api.get_dashboard_stats",
    callback: function(r) {
        if (r.message) {
            let d = r.message;

            root_element.querySelector('#existing-pvt').innerHTML = format_val(d.existing_pvt);
            root_element.querySelector('#new-client').innerHTML = format_val(d.new_client);
            root_element.querySelector('#govt-total').innerHTML = format_val(d.govt_total);
            root_element.querySelector('#turnover-score').innerHTML = format_val(d.turnover_score);

            // Display the Profit Score as a percentage
            root_element.querySelector('#profit-score').textContent = d.profit_score;

            root_element.querySelector('#count-pvt').textContent = d.new_clients_pvt;
            root_element.querySelector('#count-govt').textContent = d.new_clients_govt;
        }
    }
});

